INSERT INTO `habers` (`id`, `title`, `slug`, `image`, `excerpt`, `content`, `category`, `author`, `meta_title`, `meta_description`, `order`, `is_featured`, `created_at`, `updated_at`) VALUES
(1, 'Sürdürülebilir Temizlik: Newcity’den Çevre Dostu İnovasyon', 'surdurulebilir-temizlik-newcityden-cevre-dostu-inovasyon', 'habers/March2026/lI7CowNLS0eR7pHUWkEU.png', 'Gelecek nesillere daha temiz bir dünya bırakmak için Ar-Ge merkezimizde geliştirdiğimiz biyobozunur formüllerle sektöre öncülük ediyoruz.', '<p>Newcity olarak, &uuml;retim s&uuml;re&ccedil;lerimizde s&uuml;rd&uuml;r&uuml;lebilirliği sadece bir tercih değil, bir sorumluluk olarak g&ouml;r&uuml;yoruz. K&uuml;resel iklim krizi ve &ccedil;evre kirliliğiyle m&uuml;cadelede, temizlik sekt&ouml;r&uuml;n&uuml;n d&ouml;n&uuml;şt&uuml;r&uuml;c&uuml; g&uuml;c&uuml;ne inanıyoruz. Bu vizyonla, Konya&rsquo;daki son teknoloji Ar-Ge merkezimizde geliştirdiğimiz yeni nesil temizlik &ccedil;&ouml;z&uuml;mlerini gururla sunuyoruz.</p>\n<h3>Biyoteknoloji ve Doğanın Uyumu</h3>\n<p>Yeni geliştirdiğimiz enzim tabanlı form&uuml;llerimiz, %100 doğada &ccedil;&ouml;z&uuml;nebilir yapılarıyla su kaynaklarımızı ve ekosistemi korumayı hedefliyor. Geleneksel temizlik &uuml;r&uuml;nlerinde bulunan sert kimyasallar yerine, biyoteknolojik bileşenler kullanarak hem cildinizi hem de d&uuml;nyamızı koruyoruz. Bu form&uuml;ller, d&uuml;ş&uuml;k sıcaklıklarda (30&deg;C ve altı) bile aktifleşerek enerji t&uuml;ketimini %40&rsquo;a varan oranlarda azaltıyor, b&ouml;ylece ev ekonomisine ve karbon ayak izinin d&uuml;ş&uuml;r&uuml;lmesine doğrudan katkı sağlıyor.</p>\n<h3>Lif Onarıcı Teknoloji: Kıyafetlerinizin &Ouml;mr&uuml;n&uuml; Uzatın</h3>\n<p>Laboratuvarlarımızda geliştirilen &ouml;zel bileşenler, en zorlu lekeleri kumaş liflerine zarar vermeden molek&uuml;ler d&uuml;zeyde par&ccedil;alar. Geleneksel deterjanların aksine, Newcity form&uuml;lleri kumaşın dokusunu korur ve mikroskobik d&uuml;zeyde lif onarımı yaparak kıyafetlerinizin &ccedil;ok daha uzun s&uuml;re yeni gibi kalmasını sağlar. S&uuml;rd&uuml;r&uuml;lebilirlik, sadece form&uuml;lde değil, t&uuml;ketim alışkanlıklarımızda da başlar; daha uzun &ouml;m&uuml;rl&uuml; kıyafetler, daha az atık demektir.</p>\n<h3>Gelecek Vizyonumuz: Sıfır Atık &Uuml;retim</h3>\n<p>&Uuml;r&uuml;n i&ccedil;eriğimizin yanı sıra, ambalaj teknolojilerimizde de devrim yapıyoruz. 2026 yılı sonuna kadar t&uuml;m &uuml;r&uuml;n gruplarımızda %100 geri d&ouml;n&uuml;şt&uuml;r&uuml;lm&uuml;ş plastik ve biyoplastik ambalajlara ge&ccedil;meyi hedefliyoruz. Newcity ile temizlik, sadece y&uuml;zeylerde değil, gelecekte de parlayacak.</p>', 'İNOVASYON', 'Newcity Ar-Ge Ekibi', 'Sürdürülebilir Temizlik: Newcity’den Çevre Dostu İnovasyon | Newcity News', 'Gelecek nesillere daha temiz bir dünya bırakmak için Ar-Ge merkezimizde geliştirdiğimiz biyobozunur formüllerle sektöre öncülük ediyoruz.', 1, 1, '2026-03-13 10:16:48', '2026-03-13 10:22:25'),
(2, 'Evcil Hayvan Dostu Evler İçin Hijyen Rehberi', 'evcil-hayvan-dostu-evler-icin-hijyen-rehberi', 'habers/March2026/OfwzCYg8ItnokBngkkpQ.png', 'Patili dostlarımızın sağlığı bizim için önemli. Onlara zarar vermeyen, alerjen içermeyen temizlik çözümlerimizle tanışın.', '<p>Evcil hayvan beslenen evlerde hijyen standartları normal bir evden &ccedil;ok daha hassas olmalıdır. Sevimli dostlarımız g&uuml;n&uuml;n b&uuml;y&uuml;k b&ouml;l&uuml;m&uuml;n&uuml; zeminlerle temas halinde ge&ccedil;irir ve patilerini yalayarak temizlenirler. Bu durum, y&uuml;zey temizliğinde kullanılan kimyasalların doğrudan dostlarımızın v&uuml;cuduna girmesi riskini taşır. Newcity olarak, \"Dr. Pati\" serimizle bu riski tamamen ortadan kaldırıyoruz.</p>\n<h3>Neden Dr. Pati Serisini Tercih Etmelisiniz?</h3>\n<p>Dr. Pati serimizle geliştirdiğimiz &ccedil;&ouml;z&uuml;mler, y&uuml;zeylerde biriken bakterileri etkisiz hale getirirken, evcil hayvanlarınızın hassas patileri ve solunum yolları i&ccedil;in tamamen g&uuml;venlidir. Parf&uuml;m, amonyak, fosfat ve klor gibi sert kimyasalları form&uuml;l&uuml;m&uuml;zden tamamen &ccedil;ıkardık. Veteriner hekimler ve toksikologlar ile y&uuml;r&uuml;tt&uuml;ğ&uuml;m&uuml;z ortak &ccedil;alışmalar sonucunda, dostlarınızın sağlığını tehdit etmeyen ama hijyenden de &ouml;d&uuml;n vermeyen bir form&uuml;l yarattık.</p>\n<h3>Kalıcı Koku Kontrol&uuml; ve Derin Arınma</h3>\n<p>Evcil hayvan sahiplerinin en b&uuml;y&uuml;k zorluklarından biri olan istenmeyen kokuları, maskelemek yerine molek&uuml;ler d&uuml;zeyde yok ediyoruz. Dr. Pati Y&uuml;zey Temizleyici, kokunun kaynağı olan partik&uuml;lleri par&ccedil;alayarak evinize doğal bir ferahlık getirir. Ayrıca, alerjenleri %99 oranında azaltarak hem patili dostlarımız hem de evdeki alerjik bireyler i&ccedil;in daha yaşanabilir bir ortam sunar.</p>\n<h3>G&uuml;venli Oyun Alanları</h3>\n<p>&Uuml;r&uuml;nlerimiz durulama gerektirmeyen yapısı sayesinde pratiklik sağlar. Temizlik sonrası y&uuml;zeyde kalan bileşenler tamamen bitkisel k&ouml;kenlidir, bu da patili dostunuzun zeminle doğrudan temasında hi&ccedil;bir sakınca olmadığı anlamına gelir. Onların mutluluğu, sizin huzurunuz bizim &ouml;nceliğimizdir.</p>', 'HİJYEN', 'Veteriner Danışman Kurulu', 'Evcil Hayvan Dostu Evler İçin Hijyen Rehberi | Newcity News', 'Patili dostlarımızın sağlığı bizim için önemli. Onlara zarar vermeyen, alerjen içermeyen temizlik çözümlerimizle tanışın.', 1, 1, '2026-03-13 10:16:48', '2026-03-13 10:24:23'),
(3, 'Kozmetik ve Bakımda Yeni Trend: Doğal Bileşenler', 'kozmetik-ve-bakimda-yeni-trend-dogal-bilesenler', 'habers/March2026/f5R1S7oL4EX3rYyOVvi2.png', 'Cildinizle dost, doğadan ilham alan kişisel bakım ürünlerimizle kendinizi şımartın. Newcity Kozmetik ile tazelenin.', '<p>G&uuml;zellik ve bakım anlayışı, g&uuml;n&uuml;m&uuml;zde \"sağlıklı i&ccedil;erik\" kavramıyla yeniden şekilleniyor. Newcity Kozmetik olarak, kişisel bakım rutininizi doğanın iyileştirici g&uuml;c&uuml;yle zenginleştiriyoruz. \"Tenden Ruha Doğallık\" felsefesiyle hazırladığımız yeni &uuml;r&uuml;n serimiz, sadece dış g&ouml;r&uuml;n&uuml;ş&uuml;n&uuml;z&uuml; değil, cilt sağlığınızı da odağına alıyor.</p>\n<h3>Bitkisel &Ouml;zlerin Gizli G&uuml;c&uuml;</h3>\n<p>Kişisel bakım &uuml;r&uuml;nlerimizde kullandığımız bitkisel &ouml;zlerin kalitesini, s&uuml;rd&uuml;r&uuml;lebilir ve organik tarım ilkelerine uygun tedarik&ccedil;ilerimizden sağlıyoruz. Soğuk sıkım zeytinyağı, aloe vera, lavanta &ouml;z&uuml; ve E vitamini takviyeleriyle zenginleştirilen form&uuml;llerimiz, cildinizin doğal bariyerini desteklerken arındırıcı etkisiyle g&uuml;n boyu tazelik sağlar. Paraben, s&uuml;lfat, silikon ve yapay renklendirme i&ccedil;ermeyen &uuml;r&uuml;nlerimizle, hassas ciltler dahil her cilt tipine uygun &ccedil;&ouml;z&uuml;mler sunuyoruz.</p>\n<h3>Laboratuvardan Gelen Hassasiyet</h3>\n<p>Doğallığı bilimle birleştiriyoruz. &Uuml;r&uuml;nlerimizin her biri, dermatolojik testlerden tam not alarak raflara ulaşıyor. Mikrobiyolojik analizlerden ge&ccedil;en kozmetik serimiz, cildin pH dengesini bozmadan temizler ve nemlendirir. &Ouml;zellikle \"Anti-Aging\" etkili yeni kremlerimizde kullandığımız doğal peptitler, cilde elastikiyet kazandırarak gen&ccedil;leşme s&uuml;recini tamamen doğal yollarla destekler.</p>\n<h3>S&uuml;rd&uuml;r&uuml;lebilir G&uuml;zellik Rit&uuml;eli</h3>\n<p>Bizim i&ccedil;in g&uuml;zellik, doğaya zarar vermeden m&uuml;mk&uuml;nd&uuml;r. &Uuml;r&uuml;nlerimizin hi&ccedil;bir aşamasında hayvanlar &uuml;zerinde deney yapılmamaktadır (Cruelty-Free). Ayrıca, doğada kolayca &ccedil;&ouml;z&uuml;nen i&ccedil;eriklerimiz sayesinde banyonuzdan akıp giden suyun ekosisteme zarar vermediğinden emin olabilirsiniz. Newcity ile kendinize iyi bakın, d&uuml;nyaya iyi bakın.</p>', 'BAKIM', 'Newcity Kozmetik Lab', 'Kozmetik ve Bakımda Yeni Trend: Doğal Bileşenler | Newcity News', 'Cildinizle dost, doğadan ilham alan kişisel bakım ürünlerimizle kendinizi şımartın. Newcity Kozmetik ile tazelenin.', 2, 1, '2026-03-13 10:16:48', '2026-03-13 10:26:05'),
(4, 'Global Pazarda Newcity: İhracat Ağımız Büyüyor', 'global-pazarda-newcity-ihracat-agimiz-buyuyor', 'habers/March2026/cj6JQ5RfNh8cTM3bExel.png', 'Türkiye’den dünyaya yayılan temizlik gücü. 50’den fazla ülkeye ihraç edilen ürünlerimizle küresel bir marka olma yolunda ilerliyoruz.', '<p>Konya&rsquo;daki 20.000 metrekarelik modern &uuml;retim tesislerimizden &ccedil;ıkan Newcity &uuml;r&uuml;nleri, bug&uuml;n kıtaları aşarak d&uuml;nya devleriyle yarışıyor. Bir yerel başarı hikayesi olarak başlayan yolculuğumuz, bug&uuml;n Avrupa&rsquo;dan Amerika&rsquo;ya, Orta Doğu&rsquo;dan Uzak Doğu&rsquo;ya uzanan devasa bir ihracat ağına d&ouml;n&uuml;şt&uuml;. \"T&uuml;rk Malı\" kalitesini k&uuml;resel standartlarda temsil etmekten gurur duyuyoruz.</p>\n<h3>Uluslararası Kalite Sertifikalarıyla Onaylanmış G&uuml;&ccedil;</h3>\n<p>Markamızın yurt dışındaki başarısının anahtarı, uluslararası ge&ccedil;erliliği olan kalite y&ouml;netim sistemlerimizdir. ISO 9001, ISO 14001 ve GMP (İyi &Uuml;retim Uygulamaları) standartlarında ger&ccedil;ekleştirdiğimiz &uuml;retimimiz, her &uuml;lkenin kendi mevzuatına ve hijyen alışkanlıklarına cevap verebilecek esnekliktedir. &Ouml;zellikle Avrupa pazarındaki \"Green Label\" standartlarına uyumumuz, Newcity&rsquo;nin k&uuml;resel rekabetteki elini g&uuml;&ccedil;lendiren en &ouml;nemli unsurlardan biridir.</p>\n<h3>Yerelden Globale Stratejik Ortaklıklar</h3>\n<p>Newcity olarak sadece &uuml;r&uuml;n satmıyoruz, girdiğimiz her pazarda yerel iş ortaklarımızla stratejik bağlar kuruyoruz. Bug&uuml;n 50&rsquo;den fazla &uuml;lkede aktif satış noktalarımız ve distrib&uuml;t&ouml;r ağımızla, milyonlarca eve ulaşıyoruz. Her yıl katıldığımız uluslararası fuarlar (Amsterdam PLMA, Dubai Beautyworld vb.) sayesinde markamızın bilinirliğini artırıyor ve yeni pazarların kapısını aralıyoruz.</p>\n<h3>2030 Hedefi: D&uuml;nyanın İlk 100 Hijyen Markası</h3>\n<p>İhracat hacmimizi her yıl %30 oranında artırma hedefimizle emin adımlarla ilerliyoruz. Teknoloji yatırımlarımızı ve kapasite artış &ccedil;alışmalarımızı bu vizyon doğrultusunda şekillendiriyoruz. T&uuml;rkiye&rsquo;nin temizlik g&uuml;c&uuml;n&uuml; d&uuml;nyanın d&ouml;rt bir yanına taşımaya, \"Hijyende K&uuml;resel G&uuml;&ccedil;\" olmaya devam edeceğiz.</p>', 'KURUMSAL', 'Kurumsal İletişim', 'Global Pazarda Newcity: İhracat Ağımız Büyüyor | Newcity News', 'Türkiye’den dünyaya yayılan temizlik gücü. 50’den fazla ülkeye ihraç edilen ürünlerimizle küresel bir marka olma yolunda ilerliyoruz.', 3, 0, '2026-03-13 10:16:48', '2026-03-13 10:29:37');
INSERT INTO `hakkimizda` (`id`, `est_tag`, `stats_number`, `stats_box_number`, `factory_image`, `idea_btn_url`, `headline`, `headline_highlight`, `stats_label`, `content`, `impact_label`, `impact_title`, `stats_box_text`, `idea_title`, `idea_subtitle`, `idea_btn_text`, `seo_title`, `seo_desc`, `seo_keywords`, `created_at`, `updated_at`) VALUES
(1, 'EST. 1999', '25', '300+', NULL, '#', 'KONYA\'DAN', 'DÜNYAYA', '+ülke', '<p>New City Kimya Kozmetik Plastik ve Sağlık Ürünleri Paz. San. ve Tic. A.Ş. 2002 yılında tüketicilerin temel ihtiyaç ve gereksinimlerini karşılama, günlük hayata pratik çözüm sunan Market Ürünlerinin üretim, paketleme ve dağıtımlarını yapma adına ilk temelleri atılan ve bugün itibariyle geldiği noktada yaklaşık 8 kategori ve 300 ayrı ürün yelpazesiyle Market ve Perakende Satış Noktaları sektörüne yönelik üretim ve pazarlama faaliyetlerini yürüten NEW CITY, hızlı bir gelişme trendiyle sektöründe son derece köklü ve kurumsal bir gelişim süreci içerisinde 20.000 m2 fabrika sahası içerisinde faaliyetlerini sürdürmektedir.</p><p>Başarılı bir biçimde yürüttüğü üretim, pazarlama ve dağıtım süreci konusunda profesyonel çalışan kadrosuyla Toplam Kalite Anlayışı çerçevesinde malzeme kalitesinden sevkiyata, teknolojik ve uluslararası standartlardan, çalışan kalitesine kadar üretim ve satış sürecine son derece önem veren NEW CITY, Yurtiçinde bayii ve yurt dışında distribütör ağı ile dünyanın dört bir yanına ürün satışı gerçekleştirmektedir.</p><p>Bu başarılı gelişmenin bir sonucu olarak Temizlik, Hijyen, Mutfak Yardımcıları, Gıda Ambalaj, Kozmetik, Kişisel Bakım, Ortam Kokuları, Piknik Gereçleri, Ev Gereçleri, Evcil Hayvan Ürünleri kategorilerinde 300 ayrı ürün çeşidi ile sektöründe önemli bir boşluğu dolduran NEW CITY, müşteri memnuniyetini temel felsefe kabul eden bir anlayışla çalışmaktadır.</p><p>Tüm çalışmalarında insan ve ona karşı olan sorumluluğu temel unsur olarak en başa koyan firmamız, ayrıca gerçekleştirdiği başta Amerika, Avrupa, Ortadoğu, Afrika, Balkan Ülkeleri ve Türki Cumhuriyetlere yönelik ihracatı ile New City - Q Clean - Green Air - New Ego - New Soft - New Eco - Dr. Pati - Herkes markalarıyla ürün kalitesini ülke sınırlarının dışına taşımanın haklı gururunu yaşamaktadır.</p>', 'KÜRESEL ETKİ', '25+ Ülke\n10 Dil', 'AKTİF ÜRÜN ÇEŞİDİ', 'Geleceği Birlikte\nTasarlayalım mı?', 'Yeni bir ürün fikriniz mi var? New City İnovasyon Merkezi\'ne iletin.', 'BİR FİKRİM VAR', 'Hakkımızda | Newcity', 'New City; 2002\'den bu yana temizlik, kozmetik, gıda ambalaj ve ev ürünleri alanında Türkiye\'nin önde gelen üreticilerinden biridir.', 'newcity hakkında, new city kimya, konya üretim', '2026-03-16 09:18:13', '2026-03-16 09:18:13');
