INSERT INTO `pages` (`id`, `author_id`, `title`, `excerpt`, `body`, `image`, `slug`, `meta_description`, `meta_keywords`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, 'Hello World', 'Hang the jib grog grog blossom grapple dance the hempen jig gangway pressgang bilge rat to go on account lugger. Nelsons folly gabion line draught scallywag fire ship gaff fluke fathom case shot. Sea Legs bilge rat sloop matey gabion long clothes run a shot across the bow Gold Road cog league.', '<p>Hello World. Scallywag grog swab Cat o\'nine tails scuttle rigging hardtack cable nipper Yellow Jack. Handsomely spirits knave lad killick landlubber or just lubber deadlights chantey pinnace crack Jennys tea cup. Provost long clothes black spot Yellow Jack bilged on her anchor league lateen sail case shot lee tackle.</p>\n<p>Ballast spirits fluke topmast me quarterdeck schooner landlubber or just lubber gabion belaying pin. Pinnace stern galleon starboard warp carouser to go on account dance the hempen jig jolly boat measured fer yer chains. Man-of-war fire in the hole nipperkin handsomely doubloon barkadeer Brethren of the Coast gibbet driver squiffy.</p>', NULL, 'hello-world', 'Yar Meta Description', 'Keyword1, Keyword2', 'ACTIVE', '2025-05-20 11:11:30', '2026-03-16 09:36:50'),
(2, 1, 'Gizlilik Politikası', 'New City olarak kişisel verilerinizin güvenliği ve gizliliği bizim için önceliktir. Bu politika, hangi verileri topladığımızı, nasıl kullandığımızı ve haklarınızı açıklamaktadır.', '<h2>1. Veri Sorumlusunun Kimliği</h2>\n<p>New City Kimya Sanayi ve Ticaret A.Ş. (\"New City\" veya \"Şirket\"), 6698 sayılı Kişisel Verilerin Korunması Kanunu (\"KVKK\") kapsamında veri sorumlusu sıfatıyla hareket etmektedir. Şirketimizin iletişim bilgileri: Konya Organize Sanayi Bölgesi, Konya / Türkiye | bilgi@newcity.com.tr | +90 332 345 23 50.</p>\n\n<h2>2. Toplanan Kişisel Veriler</h2>\n<p>Web sitemizi ziyaret etmeniz veya hizmetlerimizden yararlanmanız sırasında aşağıdaki kişisel veriler toplanabilir:</p>\n<ul>\n  <li><strong>Kimlik Verileri:</strong> Ad, soyad, T.C. kimlik numarası (gerektiğinde)</li>\n  <li><strong>İletişim Verileri:</strong> E-posta adresi, telefon numarası, posta adresi</li>\n  <li><strong>İşlem Verileri:</strong> Sipariş geçmişi, teklif talepleri, form gönderimleri</li>\n  <li><strong>Teknik Veriler:</strong> IP adresi, tarayıcı türü, çerez bilgileri, oturum verileri</li>\n  <li><strong>Pazarlama Verileri:</strong> Tercihler, anket yanıtları, iletişim tercihleri</li>\n</ul>\n\n<h2>3. Kişisel Verilerin İşlenme Amaçları</h2>\n<p>Toplanan veriler aşağıdaki amaçlarla işlenmektedir:</p>\n<ul>\n  <li>Hizmetlerin sunulması ve sipariş yönetiminin gerçekleştirilmesi</li>\n  <li>Müşteri ilişkilerinin yönetimi ve destek hizmetlerinin sağlanması</li>\n  <li>Yasal yükümlülüklerin yerine getirilmesi</li>\n  <li>Web sitesi güvenliğinin ve kullanıcı deneyiminin iyileştirilmesi</li>\n  <li>Pazarlama, tanıtım ve kampanya faaliyetlerinin yürütülmesi (açık rıza dahilinde)</li>\n  <li>İstatistiksel analizler ve raporlama</li>\n</ul>\n\n<h2>4. Kişisel Verilerin Aktarılması</h2>\n<p>Kişisel verileriniz; hizmet aldığımız iş ortaklarına, kargo ve lojistik firmalarına, ödeme hizmeti sağlayıcılarına, yasal yükümlülükler kapsamında kamu kurum ve kuruluşlarına ve açık rızanız olması halinde üçüncü taraflara aktarılabilir. Yurt dışına veri aktarımı, KVKK\'nın 9. maddesindeki koşulların sağlanması halinde gerçekleştirilir.</p>\n\n<h2>5. Kişisel Verilerin Saklanma Süresi</h2>\n<p>Kişisel verileriniz, işlenme amacının gerektirdiği süre boyunca veya yasal mevzuatın öngördüğü saklama süreleri dolana kadar muhafaza edilir. Ticari ilişkiye dayalı veriler 10 yıl, müşteri kayıtları 5 yıl, teknik log verileri 2 yıl saklanır.</p>\n\n<h2>6. Veri Güvenliği</h2>\n<p>New City, kişisel verilerinizin yetkisiz erişime, değiştirilmeye, açıklanmaya veya imha edilmesine karşı SSL şifreleme, güvenlik duvarları, erişim denetim listeleri ve düzenli güvenlik denetimleri gibi uygun teknik ve idari önlemleri almaktadır.</p>\n\n<h2>7. İlgili Kişi Hakları</h2>\n<p>KVKK\'nın 11. maddesi uyarınca aşağıdaki haklara sahipsiniz:</p>\n<ul>\n  <li>Kişisel verilerinizin işlenip işlenmediğini öğrenme</li>\n  <li>İşlenmişse buna ilişkin bilgi talep etme</li>\n  <li>İşlenme amacını ve amacına uygun kullanılıp kullanılmadığını öğrenme</li>\n  <li>Yurt içinde veya yurt dışında aktarıldığı üçüncü kişileri öğrenme</li>\n  <li>Eksik veya yanlış işlenmesi halinde düzeltilmesini talep etme</li>\n  <li>KVKK\'nın 7. maddesinde öngörülen şartlar çerçevesinde silinmesini veya yok edilmesini isteme</li>\n  <li>İşlenen verilerin otomatik sistemler vasıtasıyla analiz edilmesi nedeniyle aleyhinize bir sonucun ortaya çıkmasına itiraz etme</li>\n  <li>Kanuna aykırı olarak işlenmesi nedeniyle zarara uğramanız halinde zararın giderilmesini talep etme</li>\n</ul>\n\n<h2>8. Başvuru Yöntemi</h2>\n<p>Haklarınızı kullanmak için <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> adresine e-posta göndererek veya ıslak imzalı dilekçeyle Şirket adresimize başvurabilirsiniz. Talepler, 30 gün içinde yanıtlanacaktır.</p>\n\n<h2>9. Değişiklikler</h2>\n<p>Bu politika, yasal düzenlemeler veya iş süreçlerindeki değişiklikler doğrultusunda güncellenebilir. Güncel versiyona her zaman web sitemizden ulaşabilirsiniz. Son güncelleme tarihi: Mart 2025.</p>', NULL, 'gizlilik-politikasi', 'New City Gizlilik Politikası — kişisel verilerinizin nasıl toplandığını, işlendiğini ve korunduğunu öğrenin.', 'gizlilik politikası, kişisel veri, veri koruma, New City', 'ACTIVE', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(3, 1, 'KVKK Aydınlatma Metni', '6698 sayılı Kişisel Verilerin Korunması Kanunu kapsamında New City olarak kişisel verilerinizi nasıl işlediğimizi, hangi amaçlarla kullandığımızı ve haklarınızı bu metinde bulabilirsiniz.', '<h2>1. Aydınlatma Yükümlülüğü</h2>\n<p>New City Kimya Sanayi ve Ticaret A.Ş. olarak, 6698 sayılı Kişisel Verilerin Korunması Kanunu\'nun 10. maddesi ve Aydınlatma Yükümlülüğünün Yerine Getirilmesinde Uyulacak Usul ve Esaslar Hakkında Tebliğ kapsamında veri sahiplerini bilgilendirmek amacıyla bu metni hazırladık.</p>\n\n<h2>2. Veri Sorumlusu</h2>\n<p><strong>Unvan:</strong> New City Kimya Sanayi ve Ticaret A.Ş.<br>\n<strong>Adres:</strong> Konya Organize Sanayi Bölgesi, Konya / Türkiye<br>\n<strong>E-posta:</strong> bilgi@newcity.com.tr<br>\n<strong>Telefon:</strong> +90 332 345 23 50</p>\n\n<h2>3. İşlenen Kişisel Veriler ve Kategorileri</h2>\n<p>Şirketimiz tarafından işlenen kişisel veri kategorileri ve örnekleri aşağıda yer almaktadır:</p>\n<ul>\n  <li><strong>Kimlik:</strong> Ad, soyad, doğum tarihi, T.C. kimlik numarası</li>\n  <li><strong>İletişim:</strong> Telefon, e-posta, adres, faks</li>\n  <li><strong>Finans:</strong> Banka hesap bilgileri, fatura bilgileri, ödeme geçmişi</li>\n  <li><strong>Müşteri İşlem:</strong> Sipariş, teklif, şikayet ve öneri kayıtları</li>\n  <li><strong>Pazarlama:</strong> Anket sonuçları, kampanya tercihleri, alışveriş alışkanlıkları</li>\n  <li><strong>Görsel/İşitsel:</strong> Güvenlik kamerası kayıtları (fabrika ziyaretleri)</li>\n  <li><strong>Hukuki İşlem:</strong> Sözleşme, ihtarname ve dava dosyası bilgileri</li>\n</ul>\n\n<h2>4. Kişisel Veri İşlemenin Hukuki Dayanakları</h2>\n<p>Verileriniz aşağıdaki hukuki dayanaklara göre işlenmektedir (KVKK Madde 5-6):</p>\n<ul>\n  <li>Açık rızanızın bulunması</li>\n  <li>Bir sözleşmenin kurulması veya ifasıyla doğrudan ilgili olması</li>\n  <li>Şirketimizin hukuki yükümlülüklerini yerine getirmesi</li>\n  <li>Tarafınızca alenileştirilmiş olması</li>\n  <li>Bir hakkın tesisi, kullanılması veya korunması için zorunlu olması</li>\n  <li>Meşru menfaatlerimiz için veri işlemenin zorunlu olması</li>\n</ul>\n\n<h2>5. Kişisel Verilerin İşlenme Amaçları</h2>\n<ul>\n  <li>Ürün ve hizmet satış süreçlerinin yönetimi</li>\n  <li>Sözleşme süreçlerinin yürütülmesi</li>\n  <li>Finans ve muhasebe süreçlerinin yönetimi</li>\n  <li>İnsan kaynakları süreçlerinin yürütülmesi</li>\n  <li>İletişim faaliyetlerinin yürütülmesi</li>\n  <li>Müşteri memnuniyetinin sağlanması ve şikayet yönetimi</li>\n  <li>Yasal düzenlemelere uyum ve resmi makamlarla iletişim</li>\n  <li>Bilgi güvenliği süreçlerinin yürütülmesi</li>\n  <li>Reklam, kampanya ve pazarlama süreçlerinin yönetimi (onaylı)</li>\n</ul>\n\n<h2>6. Kişisel Verilerin Aktarımı</h2>\n<p>Kişisel verileriniz; KVKK\'nın 8. ve 9. maddeleri çerçevesinde aşağıdaki taraflara aktarılabilir:</p>\n<ul>\n  <li>İş ortakları, bayiler ve tedarikçiler</li>\n  <li>Kargo ve lojistik şirketleri</li>\n  <li>Banka ve finansal kuruluşlar</li>\n  <li>Hukuk büroları ve danışmanlık firmaları</li>\n  <li>Yetkili kamu kurum ve kuruluşları (SGK, Maliye, Gümrük vb.)</li>\n  <li>Yurt dışı iş ortakları (yeterli koruma sağlandığı hallerde)</li>\n</ul>\n\n<h2>7. Veri Sahibi Hakları (KVKK Madde 11)</h2>\n<p>Veri sahibi olarak aşağıdaki haklara sahipsiniz:</p>\n<ul>\n  <li>Kişisel veri işlenip işlenmediğini öğrenme</li>\n  <li>İşlenmişse bilgi talep etme</li>\n  <li>İşlenme amacını ve amacına uygunluğunu öğrenme</li>\n  <li>Yurt içi/dışı aktarımları öğrenme</li>\n  <li>Yanlış/eksik verilerin düzeltilmesini isteme</li>\n  <li>Verilerin silinmesini veya yok edilmesini isteme</li>\n  <li>Düzeltme ve silme işlemlerinin aktarılan üçüncü kişilere bildirilmesini isteme</li>\n  <li>İşlenen verilerin otomatik analiz sonucu aleyhte kararına itiraz</li>\n  <li>Kanuna aykırı işleme nedeniyle uğranan zararın tazminini talep etme</li>\n</ul>\n\n<h2>8. Başvuru Hakkı ve Yöntemi</h2>\n<p>Yukarıda belirtilen haklarınızı kullanmak için:</p>\n<ul>\n  <li><strong>E-posta:</strong> <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> (kayıtlı e-posta veya güvenli elektronik imzalı)</li>\n  <li><strong>Posta:</strong> New City Kimya San. Tic. A.Ş., Konya OSB, Konya / Türkiye</li>\n  <li><strong>Şahsen:</strong> Şirket merkezine kimlik ibrazıyla</li>\n</ul>\n<p>Başvurularınız, talebin niteliğine göre en geç <strong>30 (otuz) gün</strong> içinde ücretsiz olarak sonuçlandırılacaktır. Taleplerin aşırı olması halinde makul bir ücret talep edilebilir.</p>\n\n<h2>9. Kişisel Verilerin Korunması Kurulu\'na Şikayet</h2>\n<p>Haklarınızın ihlal edildiğini düşünüyorsanız Kişisel Verileri Koruma Kurulu\'na (KVKK) şikayette bulunma hakkına sahipsiniz. Kurul iletişim: <a href=\"https://www.kvkk.gov.tr\" target=\"_blank\" rel=\"noopener\">www.kvkk.gov.tr</a></p>', NULL, 'kvkk-aydinlatma-metni', 'New City KVKK Aydınlatma Metni — 6698 sayılı Kanun kapsamında kişisel veri işleme amaçları, hukuki dayanaklar ve haklarınız.', 'KVKK, aydınlatma metni, kişisel veri, New City, veri işleme', 'ACTIVE', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4, 1, 'Çerez Politikası', 'New City web sitesinde hangi çerezlerin kullanıldığını, bu çerezlerin amacını ve nasıl yönetebileceğinizi bu sayfada bulabilirsiniz.', '<h2>1. Çerez Nedir?</h2>\n<p>Çerezler (cookies), web sitelerinin tarayıcınıza yerleştirdiği küçük metin dosyalarıdır. Bu dosyalar, siteyi tekrar ziyaret ettiğinizde sizi tanımlamamızı, tercihlerinizi hatırlamamızı ve ziyaret deneyiminizi kişiselleştirmemizi sağlar.</p>\n\n<h2>2. Kullandığımız Çerez Türleri</h2>\n<h3>2.1 Zorunlu Çerezler</h3>\n<p>Bu çerezler sitenin temel işlevleri için zorunludur; devre dışı bırakılamaz. Oturum yönetimi, güvenlik doğrulama ve yük dengeleme gibi amaçlarla kullanılır. Kişisel veri içermez.</p>\n<ul>\n  <li><code>XSRF-TOKEN</code> — CSRF güvenlik doğrulaması (Oturum süresi)</li>\n  <li><code>laravel_session</code> — Oturum kimliği (Oturum süresi)</li>\n  <li><code>cookie_consent</code> — Çerez onay tercihiniz (1 yıl)</li>\n</ul>\n\n<h3>2.2 Performans ve Analitik Çerezler</h3>\n<p>Ziyaretçilerin siteyi nasıl kullandığını anlamamıza yardımcı olur. Toplanan veriler anonim veya takma adlı olup bireysel kullanıcıları tanımlamaz.</p>\n<ul>\n  <li><code>_ga</code> — Google Analytics ziyaretçi tanımlayıcısı (2 yıl)</li>\n  <li><code>_gid</code> — Google Analytics oturum tanımlayıcısı (24 saat)</li>\n  <li><code>_gat</code> — Google Analytics istek hızı sınırlayıcı (1 dakika)</li>\n</ul>\n\n<h3>2.3 İşlevsellik Çerezleri</h3>\n<p>Dil tercihi, bölge ayarı ve kişiselleştirilmiş içerik gibi gelişmiş özellikleri etkinleştirmek için kullanılır.</p>\n<ul>\n  <li><code>lang_pref</code> — Dil tercihiniz (1 yıl)</li>\n  <li><code>currency</code> — Para birimi tercihiniz (30 gün)</li>\n</ul>\n\n<h3>2.4 Pazarlama ve Hedefleme Çerezleri</h3>\n<p>İlgi alanlarınıza yönelik reklamların gösterilmesi amacıyla açık rızanız alınarak kullanılır.</p>\n<ul>\n  <li><code>_fbp</code> — Facebook Pixel (3 ay)</li>\n  <li><code>_gcl_au</code> — Google Ads dönüşüm izleme (3 ay)</li>\n</ul>\n\n<h2>3. Üçüncü Taraf Çerezleri</h2>\n<p>Web sitemizde Google Analytics, YouTube içerikleri ve sosyal medya eklentileri gibi üçüncü taraf hizmetleri kullanılmaktadır. Bu hizmetler, kendi gizlilik politikaları kapsamında çerez yerleştirebilir. New City, üçüncü taraf çerezleri üzerinde doğrudan kontrol sahibi değildir.</p>\n<ul>\n  <li><a href=\"https://policies.google.com/privacy\" target=\"_blank\" rel=\"noopener\">Google Gizlilik Politikası</a></li>\n  <li><a href=\"https://www.facebook.com/privacy/policy\" target=\"_blank\" rel=\"noopener\">Meta (Facebook) Gizlilik Politikası</a></li>\n</ul>\n\n<h2>4. Çerezleri Kontrol Etme ve Devre Dışı Bırakma</h2>\n<p>Çerez tercihlerinizi tarayıcı ayarlarınız üzerinden yönetebilirsiniz. Popüler tarayıcılar için çerez yönetim rehberleri:</p>\n<ul>\n  <li><a href=\"https://support.google.com/chrome/answer/95647\" target=\"_blank\" rel=\"noopener\">Google Chrome</a></li>\n  <li><a href=\"https://support.mozilla.org/tr/kb/cerezleri-etkinlestirme-devre-disi-birakma\" target=\"_blank\" rel=\"noopener\">Mozilla Firefox</a></li>\n  <li><a href=\"https://support.apple.com/tr-tr/guide/safari/sfri11471/mac\" target=\"_blank\" rel=\"noopener\">Apple Safari</a></li>\n  <li><a href=\"https://support.microsoft.com/tr-tr/microsoft-edge/microsoft-edge-de-tanımlama-bilgileri\" target=\"_blank\" rel=\"noopener\">Microsoft Edge</a></li>\n</ul>\n<p><strong>Önemli Not:</strong> Zorunlu çerezleri devre dışı bırakmanız halinde sitenin bazı işlevleri düzgün çalışmayabilir.</p>\n\n<h2>5. Çerez Onayı</h2>\n<p>Sitemizi ilk ziyaretinizde çerez onay bildirimi görüntülenir. \"Kabul Et\" seçeneğini tıkladığınızda zorunlu çerezler dışındaki çerezlerin kullanımına onay vermiş olursunuz. Tercihlerinizi dilediğiniz zaman tarayıcı ayarlarından değiştirebilirsiniz.</p>\n\n<h2>6. Çerez Politikasının Güncellenmesi</h2>\n<p>Bu politika, mevzuat değişiklikleri veya teknolojik gelişmeler doğrultusunda güncellenebilir. Değişiklikler sitemizde yayımlandığı tarihten itibaren geçerli olacaktır. Son güncelleme tarihi: Mart 2025.</p>\n\n<h2>7. İletişim</h2>\n<p>Çerez politikamız hakkında sorularınız için <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> adresine ulaşabilirsiniz.</p>', NULL, 'cerez-politikasi', 'New City Çerez Politikası — sitemizde kullanılan çerezler, amaçları ve çerez tercihlerinizi nasıl yöneteceğiniz hakkında bilgi.', 'çerez politikası, cookie policy, GDPR, New City', 'ACTIVE', '2026-03-16 09:47:26', '2026-03-16 09:47:26');
