(4214, 'hakkimizda', 'idea_subtitle', 1, 'ru', 'Есть идея нового продукта? Поделитесь с инновационным центром New City.', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4215, 'hakkimizda', 'idea_btn_text', 1, 'ru', 'У МЕНЯ ЕСТЬ ИДЕЯ', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4216, 'hakkimizda', 'seo_title', 1, 'ru', 'О нас | Newcity', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4217, 'hakkimizda', 'seo_desc', 1, 'ru', 'New City — один из ведущих производителей Турции в области чистящих средств, косметики, пищевой упаковки и товаров для дома с 2002 года.', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4218, 'hakkimizda', 'seo_keywords', 1, 'ru', 'о newcity, new city химия, производство конья', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4219, 'hakkimizda', 'headline', 1, 'ar', 'من قونيا', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4220, 'hakkimizda', 'headline_highlight', 1, 'ar', 'إلى العالم', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4221, 'hakkimizda', 'stats_label', 1, 'ar', '+دولة', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
(4222, 'hakkimizda', 'content', 1, 'ar', '<p>تأسست شركة New City عام 2002 بهدف إنتاج وتعبئة وتوزيع منتجات تلبي الاحتياجات الأساسية للمستهلكين. اليوم تعمل الشركة في مصنع بمساحة 20,000 م2 مع 8 فئات وأكثر من 300 منتج مختلف.</p><p>بفريق محترف وبمبدأ إدارة الجودة الشاملة، تبيع NEW CITY منتجاتها في جميع أنحاء العالم من خلال شبكة موزعين محلية ودولية.</p><p>تملأ NEW CITY فراغاً مهماً في السوق بـ 300 نوعاً من المنتجات في فئات: التنظيف والنظافة، مستلزمات المطبخ، التغليف الغذائي، مستحضرات التجميل، العناية الشخصية، معطرات الجو، منتجات التخييم والحيوانات الأليفة.</p><p>تفخر الشركة بتصدير منتجاتها تحت علامات New City وQ Clean وGreen Air وNew Ego وNew Soft وNew Eco وDr. Pati وHerkes إلى أمريكا وأوروبا والشرق الأوسط وأفريقيا والبلقان والجمهوريات التركية.</p>', '2026-03-16 09:18:13', '2026-03-16 09:18:13'),
