(4249, 'pages', 'meta_description', 2, 'en', 'New City Privacy Policy — learn how your personal data is collected, processed and protected.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4250, 'pages', 'meta_keywords', 2, 'en', 'privacy policy, personal data, data protection, New City', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4251, 'pages', 'body', 2, 'en', '<h2>1. Identity of the Data Controller</h2>\n<p>New City Kimya Sanayi ve Ticaret A.Ş. (\"New City\" or \"Company\") acts as a data controller under Law No. 6698 on the Protection of Personal Data (\"KVKK\"). Contact: Konya Organized Industrial Zone, Konya / Turkey | bilgi@newcity.com.tr | +90 332 345 23 50.</p>\n\n<h2>2. Personal Data Collected</h2>\n<p>We may collect the following personal data when you visit our website or use our services:</p>\n<ul>\n  <li><strong>Identity Data:</strong> Name, surname, national ID number (when required)</li>\n  <li><strong>Contact Data:</strong> Email address, phone number, postal address</li>\n  <li><strong>Transaction Data:</strong> Order history, quote requests, form submissions</li>\n  <li><strong>Technical Data:</strong> IP address, browser type, cookie data, session data</li>\n  <li><strong>Marketing Data:</strong> Preferences, survey responses, communication preferences</li>\n</ul>\n\n<h2>3. Purposes of Processing Personal Data</h2>\n<p>Collected data is processed for the following purposes:</p>\n<ul>\n  <li>Providing services and managing orders</li>\n  <li>Managing customer relationships and support services</li>\n  <li>Fulfilling legal obligations</li>\n  <li>Improving website security and user experience</li>\n  <li>Marketing, promotion and campaign activities (with explicit consent)</li>\n  <li>Statistical analysis and reporting</li>\n</ul>\n\n<h2>4. Transfer of Personal Data</h2>\n<p>Your personal data may be transferred to our business partners, cargo and logistics companies, payment service providers, public authorities under legal obligations, and third parties with your explicit consent. Cross-border transfers are made under the conditions set out in Article 9 of KVKK.</p>\n\n<h2>5. Data Retention Period</h2>\n<p>Personal data is retained for as long as required by the processing purpose or until the statutory retention periods expire. Commercial records: 10 years, customer records: 5 years, technical logs: 2 years.</p>\n\n<h2>6. Data Security</h2>\n<p>New City implements appropriate technical and administrative measures including SSL encryption, firewalls, access control lists and regular security audits to protect your data against unauthorized access, alteration, disclosure or destruction.</p>\n\n<h2>7. Rights of Data Subjects</h2>\n<p>Under Article 11 of KVKK, you have the right to: learn whether your data is processed; request information if so; learn the purpose and whether it is used accordingly; learn third parties to whom data is transferred; request correction of incomplete or incorrect data; request deletion or destruction; object to decisions arising solely from automated processing; and seek compensation for damages arising from unlawful processing.</p>\n\n<h2>8. How to Apply</h2>\n<p>To exercise your rights, you may send an email to <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> or submit a signed petition to our registered address. Requests will be answered within 30 days.</p>\n\n<h2>9. Changes</h2>\n<p>This policy may be updated in accordance with legal regulations or changes in business processes. The current version is always available on our website. Last updated: March 2025.</p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4252, 'pages', 'title', 3, 'en', 'GDPR & Data Protection Notice', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4253, 'pages', 'slug', 3, 'en', 'data-protection-notice', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4254, 'pages', 'excerpt', 3, 'en', 'In accordance with Law No. 6698 on the Protection of Personal Data, this notice explains how New City processes your personal data, the legal bases, and your rights.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4255, 'pages', 'meta_description', 3, 'en', 'New City Data Protection Notice — purposes, legal bases and your rights under KVKK.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4256, 'pages', 'meta_keywords', 3, 'en', 'KVKK, data protection notice, personal data, New City', '2026-03-16 09:47:26', '2026-03-16 09:47:26');
INSERT INTO `translations` (`id`, `table_name`, `column_name`, `foreign_key`, `locale`, `value`, `created_at`, `updated_at`) VALUES
(4257, 'pages', 'body', 3, 'en', '<h2>1. Obligation to Inform</h2>\n<p>New City Kimya Sanayi ve Ticaret A.Ş. has prepared this notice in accordance with Article 10 of Law No. 6698 on the Protection of Personal Data and the Communiqué on Principles and Procedures for Fulfilling the Obligation to Inform.</p>\n\n<h2>2. Data Controller</h2>\n<p><strong>Name:</strong> New City Kimya Sanayi ve Ticaret A.Ş.<br>\n<strong>Address:</strong> Konya Organized Industrial Zone, Konya / Turkey<br>\n<strong>Email:</strong> bilgi@newcity.com.tr<br>\n<strong>Phone:</strong> +90 332 345 23 50</p>\n\n<h2>3. Categories of Personal Data Processed</h2>\n<ul>\n  <li><strong>Identity:</strong> Name, surname, date of birth, national ID number</li>\n  <li><strong>Contact:</strong> Phone, email, address, fax</li>\n  <li><strong>Financial:</strong> Bank account details, invoice information, payment history</li>\n  <li><strong>Customer Transaction:</strong> Orders, quotes, complaints and suggestions</li>\n  <li><strong>Marketing:</strong> Survey results, campaign preferences, shopping habits</li>\n  <li><strong>Legal:</strong> Contracts, notices and case file information</li>\n</ul>\n\n<h2>4. Legal Bases for Processing</h2>\n<ul>\n  <li>Your explicit consent</li>\n  <li>Necessity for the establishment or performance of a contract</li>\n  <li>Compliance with legal obligations</li>\n  <li>Data made public by you</li>\n  <li>Necessity for establishing, exercising or defending a legal right</li>\n  <li>Necessity for our legitimate interests</li>\n</ul>\n\n<h2>5. Purposes of Processing</h2>\n<ul>\n  <li>Management of product and service sales</li>\n  <li>Contract management</li>\n  <li>Financial and accounting processes</li>\n  <li>HR processes</li>\n  <li>Communication activities</li>\n  <li>Customer satisfaction and complaint management</li>\n  <li>Compliance with regulations and communication with authorities</li>\n  <li>Information security processes</li>\n  <li>Advertising, campaign and marketing activities (with consent)</li>\n</ul>\n\n<h2>6. Data Transfers</h2>\n<p>Personal data may be transferred to business partners, dealers, logistics companies, banks, law firms, and authorized public authorities. Cross-border transfers are made where adequate protection is ensured.</p>\n\n<h2>7. Your Rights (Article 11 of KVKK)</h2>\n<ul>\n  <li>Learn whether your data is being processed</li>\n  <li>Request information if it is being processed</li>\n  <li>Learn the purpose and whether data is used accordingly</li>\n  <li>Learn domestic/international transfers</li>\n  <li>Request correction of incorrect/incomplete data</li>\n  <li>Request deletion or destruction</li>\n  <li>Request notification to third parties of corrections or deletions</li>\n  <li>Object to decisions based on automated analysis</li>\n  <li>Claim compensation for damages from unlawful processing</li>\n</ul>\n\n<h2>8. Application Method</h2>\n<p>To exercise your rights, contact us by email at <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a>, by registered post, or in person at our headquarters. Requests will be processed within <strong>30 days</strong> free of charge.</p>\n\n<h2>9. Complaints to the Authority</h2>\n<p>If you believe your rights have been violated, you have the right to lodge a complaint with the Personal Data Protection Authority (KVKK): <a href=\"https://www.kvkk.gov.tr\" target=\"_blank\" rel=\"noopener\">www.kvkk.gov.tr</a></p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4258, 'pages', 'title', 4, 'en', 'Cookie Policy', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4259, 'pages', 'slug', 4, 'en', 'cookie-policy', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4260, 'pages', 'excerpt', 4, 'en', 'Find out what cookies are used on the New City website, their purpose, and how you can manage your cookie preferences.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4261, 'pages', 'meta_description', 4, 'en', 'New City Cookie Policy — learn about the cookies used on our site, their purposes and how to manage your preferences.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4262, 'pages', 'meta_keywords', 4, 'en', 'cookie policy, cookies, GDPR, New City', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4263, 'pages', 'body', 4, 'en', '<h2>1. What Are Cookies?</h2>\n<p>Cookies are small text files placed by websites on your browser. They allow us to recognise you on return visits, remember your preferences and personalise your browsing experience.</p>\n\n<h2>2. Types of Cookies We Use</h2>\n<h3>2.1 Strictly Necessary Cookies</h3>\n<p>These cookies are essential for the site to function and cannot be disabled. They are used for session management, security verification and load balancing. They do not contain personal data.</p>\n<ul>\n  <li><code>XSRF-TOKEN</code> — CSRF security verification (Session)</li>\n  <li><code>laravel_session</code> — Session ID (Session)</li>\n  <li><code>cookie_consent</code> — Your cookie consent preference (1 year)</li>\n</ul>\n\n<h3>2.2 Performance &amp; Analytics Cookies</h3>\n<p>These help us understand how visitors use the site. Data collected is anonymous or pseudonymous and does not identify individuals.</p>\n<ul>\n  <li><code>_ga</code> — Google Analytics visitor ID (2 years)</li>\n  <li><code>_gid</code> — Google Analytics session ID (24 hours)</li>\n  <li><code>_gat</code> — Google Analytics request rate limiter (1 minute)</li>\n</ul>\n\n<h3>2.3 Functionality Cookies</h3>\n<p>Used to enable enhanced features such as language preference and personalised content.</p>\n<ul>\n  <li><code>lang_pref</code> — Your language preference (1 year)</li>\n</ul>\n\n<h3>2.4 Marketing &amp; Targeting Cookies</h3>\n<p>Used with your explicit consent to display ads relevant to your interests.</p>\n<ul>\n  <li><code>_fbp</code> — Facebook Pixel (3 months)</li>\n  <li><code>_gcl_au</code> — Google Ads conversion tracking (3 months)</li>\n</ul>\n\n<h2>3. Third-Party Cookies</h2>\n<p>Our website uses third-party services such as Google Analytics and social media plugins, which may place their own cookies. New City does not have direct control over third-party cookies.</p>\n<ul>\n  <li><a href=\"https://policies.google.com/privacy\" target=\"_blank\" rel=\"noopener\">Google Privacy Policy</a></li>\n  <li><a href=\"https://www.facebook.com/privacy/policy\" target=\"_blank\" rel=\"noopener\">Meta (Facebook) Privacy Policy</a></li>\n</ul>\n\n<h2>4. Managing Cookies</h2>\n<p>You can manage cookies through your browser settings:</p>\n<ul>\n  <li><a href=\"https://support.google.com/chrome/answer/95647\" target=\"_blank\" rel=\"noopener\">Google Chrome</a></li>\n  <li><a href=\"https://support.mozilla.org/en-US/kb/enable-and-disable-cookies-website-preferences\" target=\"_blank\" rel=\"noopener\">Mozilla Firefox</a></li>\n  <li><a href=\"https://support.apple.com/guide/safari/manage-cookies-sfri11471/mac\" target=\"_blank\" rel=\"noopener\">Apple Safari</a></li>\n  <li><a href=\"https://support.microsoft.com/en-us/microsoft-edge/delete-cookies-in-microsoft-edge\" target=\"_blank\" rel=\"noopener\">Microsoft Edge</a></li>\n</ul>\n<p><strong>Note:</strong> Disabling strictly necessary cookies may affect site functionality.</p>\n\n<h2>5. Cookie Consent</h2>\n<p>On your first visit, a cookie consent banner will appear. By clicking \"Accept\", you consent to the use of non-essential cookies. You can change your preferences at any time via browser settings.</p>\n\n<h2>6. Policy Updates</h2>\n<p>This policy may be updated due to regulatory changes or technological developments. Changes take effect from the date published on our site. Last updated: March 2025.</p>\n\n<h2>7. Contact</h2>\n<p>For questions about our cookie policy, please contact <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a>.</p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4264, 'pages', 'title', 2, 'ru', 'Политика конфиденциальности', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4265, 'pages', 'slug', 2, 'ru', 'politika-konfidentsialnosti', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4266, 'pages', 'excerpt', 2, 'ru', 'В New City безопасность и конфиденциальность ваших персональных данных являются нашим приоритетом. В этой политике описано, какие данные мы собираем, как используем и каковы ваши права.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4267, 'pages', 'meta_description', 2, 'ru', 'Политика конфиденциальности New City — узнайте, как собираются, обрабатываются и защищаются ваши персональные данные.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4268, 'pages', 'meta_keywords', 2, 'ru', 'политика конфиденциальности, персональные данные, New City', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4269, 'pages', 'body', 2, 'ru', '<h2>1. Идентификация оператора данных</h2>\n<p>New City Kimya Sanayi ve Ticaret A.Ş. («New City» или «Компания») является оператором персональных данных в соответствии с Законом № 6698 о защите персональных данных (KVKK). Контакты: Коньяская организованная промышленная зона, Конья / Турция | bilgi@newcity.com.tr | +90 332 345 23 50.</p>\n\n<h2>2. Собираемые персональные данные</h2>\n<ul>\n  <li><strong>Идентификационные данные:</strong> Имя, фамилия, номер удостоверения личности</li>\n  <li><strong>Контактные данные:</strong> Email, телефон, почтовый адрес</li>\n  <li><strong>Данные о транзакциях:</strong> История заказов, запросы коммерческих предложений</li>\n  <li><strong>Технические данные:</strong> IP-адрес, тип браузера, файлы cookie</li>\n  <li><strong>Маркетинговые данные:</strong> Предпочтения и коммуникационные настройки</li>\n</ul>\n\n<h2>3. Цели обработки данных</h2>\n<ul>\n  <li>Предоставление услуг и управление заказами</li>\n  <li>Управление взаимоотношениями с клиентами</li>\n  <li>Исполнение юридических обязательств</li>\n  <li>Улучшение безопасности сайта и пользовательского опыта</li>\n  <li>Маркетинг и промо-акции (с согласия)</li>\n  <li>Статистический анализ</li>\n</ul>\n\n<h2>4. Передача персональных данных</h2>\n<p>Ваши данные могут передаваться деловым партнёрам, логистическим компаниям, платёжным провайдерам и государственным органам в рамках законодательных обязательств. Трансграничная передача осуществляется при соблюдении условий статьи 9 KVKK.</p>\n\n<h2>5. Сроки хранения данных</h2>\n<p>Коммерческие записи: 10 лет, клиентские записи: 5 лет, технические журналы: 2 года.</p>\n\n<h2>6. Безопасность данных</h2>\n<p>New City применяет SSL-шифрование, межсетевые экраны, списки контроля доступа и регулярные аудиты безопасности для защиты ваших данных.</p>\n\n<h2>7. Права субъектов данных</h2>\n<p>В соответствии со статьёй 11 KVKK вы вправе: узнать, обрабатываются ли ваши данные; запросить информацию; требовать исправления, удаления данных; возражать против автоматизированного принятия решений; требовать возмещения ущерба.</p>\n\n<h2>8. Способ подачи заявки</h2>\n<p>Для реализации своих прав отправьте email на <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> или письменное заявление по адресу компании. Ответ — в течение 30 дней.</p>\n\n<h2>9. Изменения</h2>\n<p>Политика может обновляться. Актуальная версия всегда доступна на сайте. Последнее обновление: март 2025.</p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4270, 'pages', 'title', 3, 'ru', 'Уведомление о защите данных', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4271, 'pages', 'slug', 3, 'ru', 'uvedomlenie-o-zashchite-dannykh', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4272, 'pages', 'excerpt', 3, 'ru', 'В соответствии с Законом № 6698 о защите персональных данных настоящее уведомление объясняет, как New City обрабатывает ваши персональные данные, правовые основания и ваши права.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4273, 'pages', 'meta_description', 3, 'ru', 'Уведомление New City о защите данных — цели обработки, правовые основания и ваши права.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4274, 'pages', 'meta_keywords', 3, 'ru', 'KVKK, защита данных, персональные данные, New City', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4275, 'pages', 'body', 3, 'ru', '<h2>1. Обязанность по информированию</h2>\n<p>New City Kimya Sanayi ve Ticaret A.Ş. подготовила настоящее уведомление в соответствии со статьёй 10 Закона № 6698 о защите персональных данных.</p>\n\n<h2>2. Оператор данных</h2>\n<p><strong>Наименование:</strong> New City Kimya Sanayi ve Ticaret A.Ş.<br>\n<strong>Адрес:</strong> Коньяская ОПЗ, Конья / Турция<br>\n<strong>Email:</strong> bilgi@newcity.com.tr | <strong>Тел:</strong> +90 332 345 23 50</p>\n\n<h2>3. Категории обрабатываемых данных</h2>\n<ul>\n  <li>Идентификационные: имя, фамилия, дата рождения, ИНН</li>\n  <li>Контактные: телефон, email, адрес</li>\n  <li>Финансовые: реквизиты, история платежей</li>\n  <li>Клиентские операции: заказы, жалобы, предложения</li>\n  <li>Маркетинговые: предпочтения, навыки совершения покупок</li>\n  <li>Правовые: договоры, судебные дела</li>\n</ul>\n\n<h2>4. Правовые основания для обработки</h2>\n<ul>\n  <li>Ваше явное согласие</li>\n  <li>Необходимость для заключения или исполнения договора</li>\n  <li>Исполнение юридических обязательств</li>\n  <li>Данные, раскрытые вами самостоятельно</li>\n  <li>Необходимость для защиты прав</li>\n  <li>Необходимость для законных интересов компании</li>\n</ul>\n\n<h2>5. Ваши права (статья 11)</h2>\n<ul>\n  <li>Узнать, обрабатываются ли данные</li>\n  <li>Запросить информацию</li>\n  <li>Требовать исправления неточных данных</li>\n  <li>Требовать удаления данных</li>\n  <li>Возражать против автоматизированного принятия решений</li>\n  <li>Требовать возмещения ущерба</li>\n</ul>\n\n<h2>6. Способ обращения</h2>\n<p>Email: <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> или письменное заявление по адресу компании. Срок ответа: <strong>30 дней</strong>.</p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4276, 'pages', 'title', 4, 'ru', 'Политика использования файлов cookie', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4277, 'pages', 'slug', 4, 'ru', 'politika-cookie', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4278, 'pages', 'excerpt', 4, 'ru', 'Узнайте, какие файлы cookie используются на сайте New City, их назначение и как управлять настройками cookie.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4279, 'pages', 'meta_description', 4, 'ru', 'Политика cookie New City — информация об используемых файлах cookie и управлении предпочтениями.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4280, 'pages', 'meta_keywords', 4, 'ru', 'политика cookie, файлы cookie, New City', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4281, 'pages', 'body', 4, 'ru', '<h2>1. Что такое файлы cookie?</h2>\n<p>Файлы cookie — небольшие текстовые файлы, сохраняемые браузером при посещении сайтов. Они позволяют нам запоминать ваши предпочтения и персонализировать опыт посещения.</p>\n\n<h2>2. Типы используемых cookie</h2>\n<h3>2.1 Строго необходимые</h3>\n<p>Необходимы для работы сайта, не могут быть отключены.</p>\n<ul>\n  <li><code>XSRF-TOKEN</code> — защита CSRF (сессия)</li>\n  <li><code>laravel_session</code> — идентификатор сессии</li>\n  <li><code>cookie_consent</code> — ваше согласие (1 год)</li>\n</ul>\n\n<h3>2.2 Аналитические</h3>\n<ul>\n  <li><code>_ga</code> — Google Analytics (2 года)</li>\n  <li><code>_gid</code> — Google Analytics (24 часа)</li>\n</ul>\n\n<h3>2.3 Функциональные</h3>\n<ul>\n  <li><code>lang_pref</code> — языковые предпочтения (1 год)</li>\n</ul>\n\n<h3>2.4 Маркетинговые</h3>\n<ul>\n  <li><code>_fbp</code> — Facebook Pixel (3 месяца)</li>\n  <li><code>_gcl_au</code> — Google Ads (3 месяца)</li>\n</ul>\n\n<h2>3. Управление cookie</h2>\n<p>Управляйте cookie через настройки браузера. Отключение необходимых cookie может нарушить работу сайта.</p>\n\n<h2>4. Изменения политики</h2>\n<p>Политика может обновляться. Последнее обновление: март 2025.</p>\n\n<h2>5. Контакты</h2>\n<p>По вопросам: <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a></p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4282, 'pages', 'title', 2, 'ar', 'سياسة الخصوصية', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4283, 'pages', 'slug', 2, 'ar', 'siyasat-alkhususiya', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4284, 'pages', 'excerpt', 2, 'ar', 'في نيو سيتي، أمن وخصوصية بياناتك الشخصية أولويتنا القصوى. تشرح هذه السياسة البيانات التي نجمعها وكيفية استخدامها وحقوقك.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4285, 'pages', 'meta_description', 2, 'ar', 'سياسة الخصوصية لنيو سيتي — تعرّف على كيفية جمع بياناتك الشخصية ومعالجتها وحمايتها.', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4286, 'pages', 'meta_keywords', 2, 'ar', 'سياسة الخصوصية، البيانات الشخصية، نيو سيتي', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4287, 'pages', 'body', 2, 'ar', '<h2>1. هوية المتحكم في البيانات</h2>\n<p>تعمل شركة New City Kimya Sanayi ve Ticaret A.Ş. («نيو سيتي» أو «الشركة») بوصفها متحكمًا في البيانات وفقًا للقانون رقم 6698 المتعلق بحماية البيانات الشخصية (KVKK). للتواصل: المنطقة الصناعية المنظمة بقونية، قونية / تركيا | bilgi@newcity.com.tr | 50 23 345 332 90+.</p>\n\n<h2>2. البيانات الشخصية المجمَّعة</h2>\n<ul>\n  <li><strong>بيانات الهوية:</strong> الاسم والكنية ورقم الهوية الوطنية</li>\n  <li><strong>بيانات الاتصال:</strong> البريد الإلكتروني والهاتف والعنوان البريدي</li>\n  <li><strong>بيانات المعاملات:</strong> سجل الطلبات وطلبات الأسعار</li>\n  <li><strong>البيانات التقنية:</strong> عنوان IP ونوع المتصفح وبيانات ملفات تعريف الارتباط</li>\n  <li><strong>بيانات التسويق:</strong> التفضيلات وتفضيلات التواصل</li>\n</ul>\n\n<h2>3. أغراض معالجة البيانات</h2>\n<ul>\n  <li>تقديم الخدمات وإدارة الطلبات</li>\n  <li>إدارة علاقات العملاء وخدمات الدعم</li>\n  <li>الوفاء بالالتزامات القانونية</li>\n  <li>تحسين أمان الموقع وتجربة المستخدم</li>\n  <li>أنشطة التسويق والترويج (بموافقة صريحة)</li>\n  <li>التحليل الإحصائي والتقارير</li>\n</ul>\n\n<h2>4. نقل البيانات الشخصية</h2>\n<p>قد تُنقَل بياناتك إلى الشركاء التجاريين وشركات الشحن ومزودي خدمات الدفع والجهات الحكومية وفقًا للالتزامات القانونية. يتم نقل البيانات عبر الحدود وفق الشروط المنصوص عليها في المادة 9 من KVKK.</p>\n\n<h2>5. مدة الاحتفاظ بالبيانات</h2>\n<p>السجلات التجارية: 10 سنوات، سجلات العملاء: 5 سنوات، السجلات التقنية: سنتان.</p>\n\n<h2>6. أمان البيانات</h2>\n<p>تطبّق نيو سيتي تشفير SSL وجدران الحماية وقوائم التحكم في الوصول وعمليات التدقيق الأمني الدورية.</p>\n\n<h2>7. حقوق أصحاب البيانات</h2>\n<p>وفقًا للمادة 11 من KVKK، يحق لك: معرفة ما إذا كانت بياناتك تُعالَج؛ طلب المعلومات؛ طلب تصحيح أو حذف البيانات؛ الاعتراض على القرارات الآلية؛ وطلب التعويض عن الأضرار.</p>\n\n<h2>8. كيفية التقدم بطلب</h2>\n<p>أرسل بريدًا إلكترونيًا إلى <a href=\"mailto:bilgi@newcity.com.tr\">bilgi@newcity.com.tr</a> أو عريضة موقَّعة إلى عنوان الشركة. سيُجاب على الطلبات خلال 30 يومًا.</p>\n\n<h2>9. التغييرات</h2>\n<p>قد تُحدَّث هذه السياسة. تاريخ آخر تحديث: مارس 2025.</p>', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
(4288, 'pages', 'title', 3, 'ar', 'إشعار حماية البيانات', '2026-03-16 09:47:26', '2026-03-16 09:47:26'),
