INSERT INTO `u_uruns` (`id`, `category_id`, `name`, `slug`, `image`, `gallery`, `short_description`, `description`, `product_code`, `volume`, `production_place`, `hs_code`, `barcode`, `barcode_text`, `badge_text`, `badge_icon`, `badge_right_text`, `order`, `status`, `seo_title`, `seo_keywords`, `seo_desc`, `seo_desc2`, `created_at`, `updated_at`) VALUES
(116, 1, 'Konsantre Çamaşır Deterjanı - Beyazlar 2145 Ml', 'konsantre-camasir-deterjani-beyazlar-2145-ml-t053', 'products/temizlik-hijyen/t053.jpg', NULL, NULL, 'Beyaz çamaşırlar, zamanla grileşme ve parlaklık kaybına en yatkın tekstil grubudur. Newcity\nKonsantre Çamaşır Deterjanı Beyazlar, beyaz kumaşlar için özel olarak geliştirilmiş güçlü\nformülü sayesinde derinlemesine temizlik sunarken çamaşırların daha aydınlık ve canlı\ngörünmesine yardımcı olur.\nKonsantre yapısı sayesinde az miktar ürünle yüksek temizlik performansı sağlar. Günlük\nkirlerin yanı sıra zorlu lekelerde de etkili sonuçlar sunan formülü, çamaşır liflerine zarar\nvermeden hijyen sağlar. Düşük ve yüksek sıcaklıklarda etkin çalışarak farklı yıkama\nprogramlarına uyum gösterir.\nEvsel kullanımın yanı sıra otel, yurt ve profesyonel çamaşırhane gibi yoğun yıkama yapılan\nalanlar için de ideal bir çözümdür. Düzenli kullanımda beyaz çamaşırların ilk günkü\ngörünümünü korumaya destek olur.', 'T-053', '2145 Ml', 'Konya, Türkiye', '3402.90.90.00.16', '869743692053', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 1, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:32', '2026-03-16 07:30:32'),
(117, 1, 'Konsantre Çamaşır Deterjanı - Renkliler 2145 Ml', 'konsantre-camasir-deterjani-renkliler-2145-ml-t054', 'products/temizlik-hijyen/t054.jpg', NULL, NULL, 'Renkli çamaşırlar, yanlış deterjan kullanımında kısa sürede solma ve matlaşma yaşayabilir.\nNewcity Konsantre Çamaşır Deterjanı Renkliler, renk koruyucu özellikleri sayesinde\nkumaşlardaki canlı tonların uzun süre muhafaza edilmesine yardımcı olur.\nYoğun konsantre formülü, az dozda yüksek temizlik gücü sunarak günlük kir ve lekeleri etkili\nşekilde temizler. Renklerin birbirine karışmasını azaltan yapısı sayesinde güvenli bir yıkama\ndeneyimi sağlar. Çamaşır üzerinde kalıntı bırakmayan formülü, hem pamuklu hem sentetik\nkumaşlarda rahatlıkla kullanılabilir.\nRenkli kıyafetlerin daha uzun süre yeni görünmesini isteyen kullanıcılar için geliştirilmiş bu\nürün, evsel ve profesyonel kullanımda pratik ve ekonomik bir temizlik çözümüdür.', 'T-054', '2145 Ml', 'Konya, Türkiye', '3402.90.90.00.16', '869743692054', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 2, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:33', '2026-03-16 07:30:33'),
(118, 1, 'Konsantre Çamaşır Deterjanı - Siyahlar 2145 Ml', 'konsantre-camasir-deterjani-siyahlar-2145-ml-t057', 'products/temizlik-hijyen/t057.jpg', NULL, NULL, 'Siyah ve koyu renkli çamaşırlar, yıkama sırasında solmaya ve iz oluşumuna daha yatkındır.\nNewcity Konsantre Çamaşır Deterjanı Siyahlar, siyah ve koyu tonlu giysiler için özel\nolarak geliştirilmiş formülüyle renk kaybını azaltmaya yardımcı olur.\nKumaş liflerine nazik davranan yapısı, giysilerin yüzeyinde oluşabilecek beyaz izleri\nminimuma indirir. Konsantre içeriği sayesinde düşük dozda yüksek performans sunarak\nekonomik kullanım avantajı sağlar. Günlük kullanımda çamaşırların daha uzun süre canlı ve\nbakımlı görünmesine katkı sağlar.\nÖzellikle siyah tişört, pantolon ve dış giyim ürünlerinde güvenle tercih edilebilecek bir\ntemizlik çözümüdür.', 'T-057', '2145 Ml', 'Konya, Türkiye', '3402.90.90.00.16', '869743692057', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 3, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:33', '2026-03-16 07:30:33'),
(119, 1, 'Konsantre Yumuşatıcı Amour 1440 Ml', 'konsantre-yumusatici-amour-1440-ml-t710', 'products/temizlik-hijyen/t710.jpg', NULL, '', '<p>Newcity Konsantre Yumuşatıcı, &ccedil;amaşırlara uzun s&uuml;re kalıcı ferahlık ve ekstra yumuşaklık kazandırmak i&ccedil;in geliştirilmiştir. Konsantre form&uuml;l&uuml; sayesinde az miktar &uuml;r&uuml;nle etkili sonu&ccedil; elde edilir ve ekonomik kullanım sağlar. Kumaş liflerini yumuşatarak &ccedil;amaşırların daha rahat kullanılmasına yardımcı olurken, statik elektrik oluşumunu azaltır. &Uuml;t&uuml; kolaylığı sağlayan yapısı, &ouml;zellikle pamuklu ve sentetik tekstillerde fark edilir bir konfor sunar. Evsel kullanımın yanı sıra otel, yurt ve profesyonel &ccedil;amaşırhane gibi alanlarda da tercih edilebilecek g&uuml;&ccedil;l&uuml; bir yumuşatma performansı sunar</p>', 'T-710', '1440 Ml', 'Konya, Türkiye', '3402.50.90.00.16', '869743692710', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 4, 1, '', '', '', '', '2026-03-16 07:30:34', '2026-03-16 07:46:23'),
(120, 1, 'Konsantre Yumuşatıcı Love 1440 Ml', 'konsantre-yumusatici-love-1440-ml-t711', 'products/temizlik-hijyen/t711.jpg', NULL, NULL, 'Newcity Konsantre Yumuşatıcı, çamaşırlara uzun süre kalıcı ferahlık ve ekstra yumuşaklık\nkazandırmak için geliştirilmiştir. Konsantre formülü sayesinde az miktar ürünle etkili sonuç\nelde edilir ve ekonomik kullanım sağlar.\nKumaş liflerini yumuşatarak çamaşırların daha rahat kullanılmasına yardımcı olurken, statik\nelektrik oluşumunu azaltır. Ütü kolaylığı sağlayan yapısı, özellikle pamuklu ve sentetik\ntekstillerde fark edilir bir konfor sunar.\nEvsel kullanımın yanı sıra otel, yurt ve profesyonel çamaşırhane gibi alanlarda da tercih\nedilebilecek güçlü bir yumuşatma performansı sunar', 'T-711', '1440 Ml', 'Konya, Türkiye', '3402.50.90.00.16', '869743692711', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 5, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:35', '2026-03-16 07:30:35'),
(121, 1, 'Konsantre Yumuşatıcı Romantic1440 Ml', 'konsantre-yumusatici-romantic1440-ml-t712', 'products/temizlik-hijyen/t712.jpg', NULL, NULL, 'Newcity Konsantre Yumuşatıcı, çamaşırlara uzun süre kalıcı ferahlık ve ekstra yumuşaklık\nkazandırmak için geliştirilmiştir. Konsantre formülü sayesinde az miktar ürünle etkili sonuç\nelde edilir ve ekonomik kullanım sağlar.\nKumaş liflerini yumuşatarak çamaşırların daha rahat kullanılmasına yardımcı olurken, statik\nelektrik oluşumunu azaltır. Ütü kolaylığı sağlayan yapısı, özellikle pamuklu ve sentetik\ntekstillerde fark edilir bir konfor sunar.\nEvsel kullanımın yanı sıra otel, yurt ve profesyonel çamaşırhane gibi alanlarda da tercih\nedilebilecek güçlü bir yumuşatma performansı sunar', 'T-712', '1440 Ml', 'Konya, Türkiye', '3402.50.90.00.16', '869743692712', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 6, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:36', '2026-03-16 07:30:36'),
(122, 1, 'Konsantre Yumuşatıcı Sensetive 1440 Ml', 'konsantre-yumusatici-sensetive-1440-ml-t713', 'products/temizlik-hijyen/t713.jpg', NULL, NULL, 'Newcity Konsantre Yumuşatıcı, çamaşırlara uzun süre kalıcı ferahlık ve ekstra yumuşaklık\nkazandırmak için geliştirilmiştir. Konsantre formülü sayesinde az miktar ürünle etkili sonuç\nelde edilir ve ekonomik kullanım sağlar.\nKumaş liflerini yumuşatarak çamaşırların daha rahat kullanılmasına yardımcı olurken, statik\nelektrik oluşumunu azaltır. Ütü kolaylığı sağlayan yapısı, özellikle pamuklu ve sentetik\ntekstillerde fark edilir bir konfor sunar.\nEvsel kullanımın yanı sıra otel, yurt ve profesyonel çamaşırhane gibi alanlarda da tercih\nedilebilecek güçlü bir yumuşatma performansı sunar', 'T-713', '1440 Ml', 'Konya, Türkiye', '3402.50.90.00.16', '869743692713', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 7, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:37', '2026-03-16 07:30:37'),
(123, 1, 'Yumuşatıcı Romantic 4 Kg', 'yumusatici-romantic-4-kg-e229', 'products/temizlik-hijyen/e229.jpg', NULL, NULL, 'Newcity Yumuşatıcı, çamaşırların yıkama sonrası daha yumuşak, ferah ve hoş kokulu\nolmasını sağlar. Günlük kullanım için dengeli formülü sayesinde kumaşlara zarar vermeden\nkonforlu bir kullanım deneyimi sunar.\nÇamaşır liflerini sararak sertliği azaltır, giysilerin ciltle temasını daha rahat hale getirir. Hoş\nkokusu yıkama sonrası uzun süre hissedilir ve çamaşırlara ferahlık kazandırır.\nEvde günlük çamaşır yıkamalarında güvenle tercih edilebilecek pratik bir temizlik\ntamamlayıcısıdır.', 'E-229', '4 Kg', 'Konya, Türkiye', '3401.20.90.90.11', '869743692229', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 8, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:38', '2026-03-16 07:30:38'),
(124, 1, 'Yumuşatıcı Sensetive 4 Kg', 'yumusatici-sensetive-4-kg-e230', 'products/temizlik-hijyen/e230.jpg', NULL, NULL, 'Newcity Yumuşatıcı, çamaşırların yıkama sonrası daha yumuşak, ferah ve hoş kokulu\nolmasını sağlar. Günlük kullanım için dengeli formülü sayesinde kumaşlara zarar vermeden\nkonforlu bir kullanım deneyimi sunar.\nÇamaşır liflerini sararak sertliği azaltır, giysilerin ciltle temasını daha rahat hale getirir. Hoş\nkokusu yıkama sonrası uzun süre hissedilir ve çamaşırlara ferahlık kazandırır.\nEvde günlük çamaşır yıkamalarında güvenle tercih edilebilecek pratik bir temizlik\ntamamlayıcısıdır.', 'E-230', '4 Kg', 'Konya, Türkiye', '3401.20.90.90.11', '869743692230', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 9, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:39', '2026-03-16 07:30:39'),
(125, 1, 'Yumuşatıcı Love 4 Kg', 'yumusatici-love-4-kg-e378', 'products/temizlik-hijyen/e378.jpg', NULL, NULL, 'Newcity Yumuşatıcı, çamaşırların yıkama sonrası daha yumuşak, ferah ve hoş kokulu\nolmasını sağlar. Günlük kullanım için dengeli formülü sayesinde kumaşlara zarar vermeden\nkonforlu bir kullanım deneyimi sunar.\nÇamaşır liflerini sararak sertliği azaltır, giysilerin ciltle temasını daha rahat hale getirir. Hoş\nkokusu yıkama sonrası uzun süre hissedilir ve çamaşırlara ferahlık kazandırır.\nEvde günlük çamaşır yıkamalarında güvenle tercih edilebilecek pratik bir temizlik\ntamamlayıcısıdır.', 'E-378', '4 Kg', 'Konya, Türkiye', '3401.20.90.90.11', '869743692378', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 10, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:40', '2026-03-16 07:30:40'),
(126, 1, 'Yüzey Temizleyici  Çiçek Bahçesi 2500 Ml', 'yuzey-temizleyici-cicek-bahcesi-2500-ml-t386', 'products/temizlik-hijyen/t386.jpg', NULL, NULL, 'Newcity Yüzey Temizleyici, ev ve iş yerlerinde sık temas edilen yüzeylerin hijyenik ve ferah\nbir şekilde temizlenmesi için geliştirilmiştir. Günlük kir, toz ve lekeleri etkili şekilde\ntemizlerken yüzeylerde kalıntı bırakmaz.\nFarklı yüzey türlerine uyumlu formülü sayesinde masa, tezgâh, dolap, kapı ve benzeri\nalanlarda güvenle kullanılabilir. Hoş kokusu temizlik sonrası ferahlık hissi yaratırken, pratik\nkullanımıyla günlük temizlik rutinlerini kolaylaştırır.\nEvsel kullanımın yanı sıra ofis, mağaza ve ortak alan temizliği için de ideal bir çözüm sunar.', 'T-386', '2500 Ml', 'Konya, Türkiye', '3402.50.90.00.16', '869743692386', NULL, 'Laboratuvar Onaylı Formül', 'verified_user', 'ISO 9001', 11, 1, NULL, NULL, NULL, NULL, '2026-03-16 07:30:41', '2026-03-16 07:30:41'),
